// Usar instanceof para responder diferente a cada error
function procesarDato(dato) {
  try {
    if (typeof dato !== 'string') throw new TypeError('Se esperaba un string');
    const parsed = JSON.parse(dato);
    return parsed;
  } catch (error) {
    if (error instanceof TypeError) {
      return { error: 'tipo', mensaje: error.message };
    }
    if (error instanceof SyntaxError) {
      return { error: 'sintaxis', mensaje: 'JSON invÃĄlido' };
    }
    throw error; // relanza errores inesperados
  }
}

console.log(procesarDato(42));         // { error: 'tipo', ... }
console.log(procesarDato('invÃĄlido')); // { error: 'sintaxis', ... }
console.log(procesarDato('{"a":1}')); // { a: 1 }

